'use strict';
/**
 * Unit tests for lib/cache — sliding window + maxAge expiration.
 *
 * Run: node `which nodeunit` test/node_modules/cache/test/01-cache.js
 *
 * Sub-second TTLs (e.g. ttl: 0.1) are used throughout so the suite
 * completes in < 2 s. lib/cache uses Math.round(value.ttl * 1000) for
 * all timer durations, so fractional seconds are fully supported.
 * Each test is self-contained with its own Cache instance.
 */
var Cache = require('../index');

// ---------------------------------------------------------------------------
// 1. Basic absolute TTL (existing behaviour, unchanged)
// ---------------------------------------------------------------------------

exports['Absolute TTL: entry expires after ttl seconds'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v', ttl: 0.1 });
    test.ok(c.get('k') !== undefined, 'entry should exist immediately after set');
    setTimeout(function() {
        test.equal(c.get('k'), undefined, 'entry should be gone after TTL');
        test.done();
    }, 150);
};

exports['Absolute TTL: entry persists before expiry'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v', ttl: 0.5 });
    setTimeout(function() {
        test.ok(c.get('k') !== undefined, 'entry should still be alive within TTL');
        c.delete('k');
        test.done();
    }, 100);
};

exports['No TTL: entry persists indefinitely'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v' });
    setTimeout(function() {
        test.ok(c.get('k') !== undefined, 'entry without TTL should still be alive');
        c.delete('k');
        test.done();
    }, 50);
};

// ---------------------------------------------------------------------------
// 2. createdAt and lastAccessedAt stamped at write time
// ---------------------------------------------------------------------------

exports['set() stamps createdAt and lastAccessedAt'] = function(test) {
    var c = new Cache();
    var before = Date.now();
    c.set('k', { content: 'v', ttl: 0.5 });
    var v = c.get('k');
    var after = Date.now();
    test.ok(v.createdAt instanceof Date, 'createdAt should be a Date');
    test.ok(v.lastAccessedAt instanceof Date, 'lastAccessedAt should be a Date');
    test.ok(v.createdAt.getTime() >= before && v.createdAt.getTime() <= after, 'createdAt should be in range');
    test.equal(v.createdAt.getTime(), v.lastAccessedAt.getTime(), 'lastAccessedAt should equal createdAt right after set()');
    c.delete('k');
    test.done();
};

// ---------------------------------------------------------------------------
// 3. Sliding TTL — pure (no maxAge)
// ---------------------------------------------------------------------------

exports['Sliding: entry stays alive while accessed within window'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v', ttl: 0.2, sliding: true }); // 200 ms window

    // Access at 120 ms — within the 200 ms window, resets it
    setTimeout(function() {
        var v = c.get('k');
        test.ok(v !== undefined, 'entry should be alive at 120 ms');
        test.ok(v.lastAccessedAt.getTime() > v.createdAt.getTime(), 'lastAccessedAt should be updated after get()');

        // Check at 120+80=200 ms total (80 ms since last access — within new 200 ms window)
        setTimeout(function() {
            test.ok(c.get('k') !== undefined, 'entry should be alive 80 ms after last access');

            // Wait 220 ms with no access — sliding window expires
            setTimeout(function() {
                test.equal(c.get('k'), undefined, 'entry should be gone after idle > ttl');
                test.done();
            }, 220);
        }, 80);
    }, 120);
};

exports['Sliding: entry expires when not accessed for ttl seconds'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v', ttl: 0.2, sliding: true }); // 200 ms window
    // No access — wait for the window to elapse, then check lazily via get()
    setTimeout(function() {
        test.equal(c.get('k'), undefined, 'entry should be expired after idle > ttl');
        test.done();
    }, 280);
};

// ---------------------------------------------------------------------------
// 4. Sliding TTL + maxAge (recommended combination)
// ---------------------------------------------------------------------------

exports['Sliding+maxAge: expiresAt is set on write'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v', ttl: 0.2, sliding: true, maxAge: 0.5 });
    var v = c.get('k');
    test.ok(v !== undefined, 'entry should exist immediately');
    test.ok(v.expiresAt instanceof Date, 'expiresAt should be a Date');
    test.ok(v.expiresAt.getTime() > v.createdAt.getTime(), 'expiresAt should be after createdAt');
    // expiresAt should be ~500 ms from now
    var diff = v.expiresAt.getTime() - v.createdAt.getTime();
    test.ok(diff >= 450 && diff <= 550, 'expiresAt should be createdAt + maxAge (±50 ms), got: ' + diff + ' ms');
    c.delete('k');
    test.done();
};

exports['Sliding+maxAge: absolute ceiling evicts entry even when accessed constantly'] = function(test) {
    var c = new Cache();
    // 500 ms sliding window, 200 ms absolute ceiling — ceiling fires first
    c.set('k', { content: 'v', ttl: 0.5, sliding: true, maxAge: 0.2 });
    test.ok(c.get('k') !== undefined, 'entry should be alive immediately');

    // At 80 ms: access to prove sliding window is not the cause of eviction
    setTimeout(function() {
        test.ok(c.get('k') !== undefined, 'entry should be alive at 80 ms — within maxAge');

        // At 80+160=240 ms total: maxAge (200 ms) has elapsed — entry should be gone
        setTimeout(function() {
            test.equal(c.get('k'), undefined, 'entry should be gone at 240 ms — maxAge exceeded');
            test.done();
        }, 160);
    }, 80);
};

exports['Sliding+maxAge: sliding window evicts before maxAge'] = function(test) {
    var c = new Cache();
    // 200 ms sliding window, 500 ms absolute ceiling — sliding fires first
    c.set('k', { content: 'v', ttl: 0.2, sliding: true, maxAge: 0.5 });
    // No access after write — sliding window expires at ~200 ms
    setTimeout(function() {
        test.equal(c.get('k'), undefined, 'entry should be gone after idle > ttl, well before maxAge');
        test.done();
    }, 280);
};

// ---------------------------------------------------------------------------
// 5. delete() cancels the timer and runs cleanup
// ---------------------------------------------------------------------------

exports['delete() evicts entry and runs cleanupFn'] = function(test) {
    var c = new Cache();
    var cleaned = false;
    c.set('k', { content: 'v', ttl: 0.5 }, function() { cleaned = true; });
    test.ok(c.has('k'), 'entry should exist before delete');
    c.delete('k');
    test.equal(c.has('k'), false, 'entry should be gone after delete()');
    test.equal(cleaned, true, 'cleanupFn should have been called');
    test.done();
};

exports['set() on existing key cancels old timer and replaces entry'] = function(test) {
    var c = new Cache();
    c.set('k', { content: 'v1', ttl: 0.2 }); // would expire in 200 ms
    // Overwrite before the first timer fires
    c.set('k', { content: 'v2', ttl: 1 }); // now expires in 1 s

    setTimeout(function() {
        var v = c.get('k');
        test.ok(v !== undefined, 'entry should still be alive (old 200 ms timer was cancelled)');
        test.equal(v.content, 'v2', 'entry should contain the new value');
        c.delete('k');
        test.done();
    }, 300);
};

// ---------------------------------------------------------------------------
// 6. stats() snapshot
// ---------------------------------------------------------------------------

exports['stats(): returns size and typed entries'] = function(test) {
    var c = new Cache();
    c.set('static:/about',     { content: '<h1>About</h1>', ttl: 0.5, fromMemory: true });
    c.set('data:/api/users',   { filename: '/tmp/users.json', ttl: 1, sliding: true, maxAge: 5 });
    c.set('http2session:abc',  { sessionId: 'abc' });

    var s = c.stats();
    test.equal(s.size, 3, 'size should be 3');
    test.equal(s.entries.length, 3, 'entries should have 3 items');

    var byKey = {};
    s.entries.forEach(function(e) { byKey[e.key] = e; });

    test.equal(byKey['static:/about'].type,    'memory',  'static entry type should be memory');
    test.equal(byKey['data:/api/users'].type,  'fs',      'data entry type should be fs');
    test.equal(byKey['http2session:abc'].type, 'session', 'http2session entry type should be session');

    test.equal(byKey['static:/about'].sliding,    false, 'non-sliding entry sliding should be false');
    test.equal(byKey['data:/api/users'].sliding,  true,  'sliding entry sliding should be true');

    test.ok(byKey['static:/about'].ttlRemaining   !== null, 'memory entry should have ttlRemaining');
    test.ok(byKey['data:/api/users'].ttlRemaining !== null, 'fs entry should have ttlRemaining');
    test.ok(byKey['data:/api/users'].maxAgeRemaining !== null, 'fs+maxAge entry should have maxAgeRemaining');
    test.equal(byKey['http2session:abc'].ttlRemaining, null, 'session entry with no ttl should have null ttlRemaining');

    c.clear();
    test.done();
};

// ---------------------------------------------------------------------------
// 7. clear() evicts all entries
// ---------------------------------------------------------------------------

exports['clear() removes all entries'] = function(test) {  // test 7 (renumbered)
    var c = new Cache();
    c.set('a', { content: '1', ttl: 0.5 });
    c.set('b', { content: '2', ttl: 0.5 });
    test.equal(c.size(), 2, 'should have 2 entries before clear()');
    c.clear();
    test.equal(c.size(), 0, 'should have 0 entries after clear()');
    test.equal(c.get('a'), undefined, 'a should be gone');
    test.equal(c.get('b'), undefined, 'b should be gone');
    test.done();
};
